mapper.select:
SELECT tactics_id AS tacticsId, level, create_time AS createTime
FROM user_tactics
WHERE user_id = #{userId}

SELECT tactics_id AS tacticsId, level, create_time AS createTime
FROM user_tactics
WHERE user_id = #{userId} AND tactics_id = #{tacticsId}

mapper.insert:
INSERT INTO user_tactics (user_id, tactics_id, level, create_time)
VALUES (#{userId}, #{tacticsId}, #{level}, #{createTime})
ON DUPLICATE KEY UPDATE level = #{level}
